import pandas as pd

# 使用上游已获取/汇总的小时记录结果，不重新查询数据库
summary_df = tangshan_hourly_air_quality_summary_for_synthesis_20250602
peak_df = tangshan_peak_aqi_hour_for_synthesis_20250602

if summary_df is None or len(summary_df) == 0:
    raise ValueError("上游汇总结果为空，无法赋值 mean_aqi、max_aqi、max_pm25。")

summary_row = summary_df.iloc[0]

def _get_first_existing(row_or_df, candidate_names):
    for name in candidate_names:
        if name in row_or_df.index if hasattr(row_or_df, "index") else name in row_or_df.columns:
            return row_or_df[name]
    raise KeyError(f"未找到候选字段：{candidate_names}")

mean_aqi = float(_get_first_existing(summary_row, ["mean_aqi", "avg_aqi", "aqi_mean"]))
max_aqi = float(_get_first_existing(summary_row, ["max_aqi", "aqi_max"]))
max_pm25 = float(_get_first_existing(summary_row, ["max_pm25", "max_pm2_5", "pm25_max", "pm2_5_max"]))

if peak_df is None or len(peak_df) == 0:
    raise ValueError("上游峰值小时结果为空，无法赋值 peak_aqi_hour_of_day。")

peak_row = peak_df.iloc[0]
if "peak_aqi_hour_of_day" in peak_row.index:
    peak_aqi_hour_of_day = int(peak_row["peak_aqi_hour_of_day"])
elif "hour_of_day" in peak_row.index:
    peak_aqi_hour_of_day = int(peak_row["hour_of_day"])
elif "hour" in peak_row.index:
    peak_aqi_hour_of_day = int(peak_row["hour"])
elif "timestamp" in peak_row.index:
    peak_aqi_hour_of_day = int(pd.to_datetime(peak_row["timestamp"]).hour)
else:
    raise KeyError("上游峰值小时结果中未找到可用于确定小时的字段。")

if not (0 <= peak_aqi_hour_of_day <= 23):
    raise ValueError(f"peak_aqi_hour_of_day 超出 0-23 范围：{peak_aqi_hour_of_day}")

print("mean_aqi =", mean_aqi)
print("max_aqi =", max_aqi)
print("max_pm25 =", max_pm25)
print("peak_aqi_hour_of_day =", peak_aqi_hour_of_day)
